CustomField.formula:
IF(NOT(ISBLANK(DX_Resolution_Date__c)),ROUND( 8 * ( 
( 5 * FLOOR( ( DX_Resolution_Date__c  - DATE( 1900, 1, 8) ) / 7) + 
MIN(5, 
MOD( DX_Resolution_Date__c  - DATE( 1900, 1, 8), 7) + 
MIN( 1, 24 / 8 * ( MOD(DX_Resolution_Date__c - DATE( 1900, 1, 8 ), 1 ) ) ) 
) 
) 
- 
( 5 * FLOOR( ( DX_Date_Received__c  - DATE( 1900, 1, 8) ) / 7) + 
MIN( 5, 
MOD( DX_Date_Received__c - DATE( 1996, 1, 1), 7 ) + 
MIN( 1, 24 / 8 * ( MOD( DX_Date_Received__c - DATE( 1900, 1, 8 ), 1) ) ) 
) 
) 
), 
0 )/8, NULL)
